"use client";

import { motion } from "motion/react";
import { forwardRef, type HTMLAttributes, useEffect, useState } from "react";

import { cn } from "@/lib/utils";

const lightTokens = [
  "[--background:#ffffff]",
  "[--foreground:#111111]",
  "[--primary:#111111]",
  "[--secondary:#646b75]",
  "[--surface-border:#e9edf2]",
  "[--border:#e3e7ec]",
  "[--card:#ffffff]",
  "[--card-foreground:#111111]",
  "[--muted:#f5f7fa]",
  "[--muted-foreground:#6d7480]",
  "[--accent:#f3f5f8]",
  "[--accent-foreground:#111111]",
  "[--input:#e3e7ec]",
  "[--ring:rgba(17,17,17,0.16)]",
  "[--destructive:#dc2626]",
  "[--paper:#fcfcfd]",
  "[--popover-foreground:#111111]",
  "[--brand:#0ea5e9]",
  "[--brand-soft:#bae6fd]",
  "[--shadow-soft:0_18px_38px_-24px_rgba(15,23,42,0.35)]",
];

const aliasTokens = [
  "[--color-background:var(--background)]",
  "[--color-foreground:var(--foreground)]",
  "[--color-primary:var(--primary)]",
  "[--color-secondary:var(--secondary)]",
  "[--color-border:var(--border)]",
  "[--color-card:var(--card)]",
  "[--color-card-foreground:var(--card-foreground)]",
  "[--color-muted:var(--muted)]",
  "[--color-muted-foreground:var(--muted-foreground)]",
  "[--color-accent:var(--accent)]",
  "[--color-accent-foreground:var(--accent-foreground)]",
  "[--color-input:var(--input)]",
  "[--color-ring:var(--ring)]",
  "[--color-destructive:var(--destructive)]",
  "[--color-paper:var(--paper)]",
  "[--color-popover-foreground:var(--popover-foreground)]",
  "[--color-brand:var(--brand)]",
  "[--color-brand-soft:var(--brand-soft)]",
];

const darkTokens = [
  "dark:[--background:#111111]",
  "dark:[--foreground:#f6f3ec]",
  "dark:[--primary:#f6f3ec]",
  "dark:[--secondary:#cbc6bb]",
  "dark:[--surface-border:#2a2a25]",
  "dark:[--border:#2b2a25]",
  "dark:[--card:#111111]",
  "dark:[--card-foreground:#f6f3ec]",
  "dark:[--muted:#171716]",
  "dark:[--muted-foreground:#9a958a]",
  "dark:[--accent:#1a1a18]",
  "dark:[--accent-foreground:#f6f3ec]",
  "dark:[--input:#2b2a25]",
  "dark:[--ring:rgba(246,243,236,0.18)]",
  "dark:[--destructive:#f87171]",
  "dark:[--paper:#171716]",
  "dark:[--popover-foreground:#f6f3ec]",
  "dark:[--brand:#38bdf8]",
  "dark:[--brand-soft:#0c4a6e]",
  "dark:[--shadow-soft:0_20px_44px_-28px_rgba(0,0,0,0.6)]",
];

const registryTheme = [
  ...lightTokens,
  ...aliasTokens,
  ...darkTokens,
].join(" ");

/** Keeps the visible avatar and image footprint aligned to a 44px target. */
const AVATAR_SIZE = 44;
const WHITESPACE_REGEX = /\s+/g;
const FALLBACK_SPLIT_REGEX = /[\s_-]+/;
const NON_ALPHANUMERIC_REGEX = /[^\p{L}\p{N}]+/gu;

type DivHTMLAttributesForMotion = Omit<
  HTMLAttributes<HTMLDivElement>,
  | "children"
  | "onAnimationEnd"
  | "onAnimationIteration"
  | "onAnimationStart"
  | "onDrag"
  | "onDragEnd"
  | "onDragEnter"
  | "onDragExit"
  | "onDragLeave"
  | "onDragOver"
  | "onDragStart"
  | "onDrop"
>;

export interface AvatarProps extends DivHTMLAttributesForMotion {
  src?: string;
  fallback?: string;
  alt?: string;
  name?: string;
  loading?: "eager" | "lazy";
  className?: string;
}

const enterEase = [0.16, 1, 0.3, 1] as const;
const settleEase = [0.22, 1, 0.36, 1] as const;

function normalizeText(value?: string) {
  return value?.trim().replace(WHITESPACE_REGEX, " ") ?? "";
}

function firstCharacter(value: string) {
  return Array.from(value)[0] ?? "";
}

function getFallbackLabel(fallback?: string, name?: string, alt?: string) {
  const normalized = [fallback, name, alt].map(normalizeText).find(Boolean);

  if (!normalized) {
    return "?";
  }

  const words = normalized
    .split(FALLBACK_SPLIT_REGEX)
    .map((word) => word.replace(NON_ALPHANUMERIC_REGEX, ""))
    .filter(Boolean);

  if (words.length >= 2) {
    return `${firstCharacter(words[0])}${firstCharacter(words[1])}`.toUpperCase();
  }

  const compact = Array.from(
    words[0] ?? normalized.replace(WHITESPACE_REGEX, "")
  )
    .slice(0, 2)
    .join("");

  return compact.toUpperCase() || "?";
}

function getAltText(alt?: string, name?: string) {
  if (alt !== undefined) {
    return normalizeText(alt);
  }

  const normalizedName = normalizeText(name);
  return normalizedName || "Avatar";
}

const Avatar = forwardRef<HTMLDivElement, AvatarProps>(
  (
    { src, fallback = "?", alt, name, loading = "eager", className, ...props },
    ref
  ) => {
    const fallbackLabel = getFallbackLabel(fallback, name, alt);
    const altText = getAltText(alt, name);
    const [imageStatus, setImageStatus] = useState<"idle" | "loaded" | "error">(
      src ? "idle" : "error"
    );

    useEffect(() => {
      setImageStatus(src ? "idle" : "error");
    }, [src]);

    const rootTransition = { duration: 0.2, ease: settleEase };

    const imageTransition = { duration: 0.22, ease: enterEase };

    const fallbackTransition = { duration: 0.18, ease: settleEase };

    return (
      <motion.div
        animate={{ opacity: 1, scale: 1 }}
        className={cn(
          registryTheme,
          "relative inline-flex h-11 w-11 shrink-0 items-center justify-center overflow-hidden rounded-full bg-primary text-background",
          className
        )}
        initial={{ opacity: 0, scale: 0.98 }}
        ref={ref}
        transition={rootTransition}
        {...props}
      >
        <motion.span
          animate={
            imageStatus === "loaded"
              ? { opacity: 0, scale: 0.96 }
              : { opacity: 1, scale: 1 }
          }
          className="absolute inset-0 flex select-none items-center justify-center font-semibold text-sm uppercase tracking-[0.08em]"
          initial={false}
          transition={fallbackTransition}
        >
          {fallbackLabel}
        </motion.span>

        {src ? (
          <motion.div
            animate={
              imageStatus === "loaded"
                ? { opacity: 1, scale: 1 }
                : { opacity: 0, scale: 1.02 }
            }
            className="relative h-full w-full overflow-hidden rounded-full"
            initial={false}
            transition={imageTransition}
          >
            {/* biome-ignore lint/performance/noImgElement: registry component stays framework-agnostic for shadcn consumers outside Next.js. */}
            <img
              alt={altText}
              className="h-full w-full object-cover"
              decoding="async"
              height={AVATAR_SIZE}
              loading={loading}
              onError={() => setImageStatus("error")}
              onLoad={() => setImageStatus("loaded")}
              src={src}
              width={AVATAR_SIZE}
            />
          </motion.div>
        ) : null}

        <div
          aria-hidden
          className="pointer-events-none absolute inset-0 rounded-full ring-1 ring-white/20 ring-inset dark:ring-black/20"
        />
      </motion.div>
    );
  }
);

Avatar.displayName = "Avatar";

export { Avatar as avatar };
export { Avatar };
